function ServiceHealthGridWidget() {
  const [services, setServices] = React.useState([
    { name: 'API Gateway', status: 'up' },
    { name: 'Auth Service', status: 'up' },
    { name: 'Database', status: 'down' },
    { name: 'Cache', status: 'up' },
    { name: 'Queue Worker', status: 'up' },
    { name: 'CDN', status: 'up' },
    { name: 'Search', status: 'degraded' },
    { name: 'Notifications', status: 'up' }
  ]);

  function color(status) {
    if (status === 'up') return '#22c55e';
    if (status === 'degraded') return '#f59e0b';
    return '#ef4444';
  }

  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: 16, background: '#0f172a', color: '#e2e8f0', borderRadius: 12, height: '100%' }}>
      <h3 style={{ margin: 0, marginBottom: 12 }}>Service Health</h3>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: 10 }}>
        {services.map((s) => (
          <div key={s.name} style={{ display: 'flex', alignItems: 'center', gap: 10, background: '#1e293b', padding: 10, borderRadius: 8 }}>
            <div style={{ width: 10, height: 10, borderRadius: '50%', background: color(s.status) }} />
            <div style={{ fontSize: 13 }}>{s.name}</div>
          </div>
        ))}
      </div>
      <div style={{ marginTop: 12, fontSize: 11, color: '#64748b' }}>Auto-refreshes every 30s</div>
    </div>
  );
}
render(<ServiceHealthGridWidget/>);
